import React from "react";

function Contact() {
  return (
    <div className="contact-page">
      <div className="contact-box">
        <h1>Contact Us</h1>
        <p>Email: careers@jobportal.com</p>
        <p>Phone: +91 9876543210</p>
        <p>Address: Hyderabad, India</p>
      </div>
    </div>
  );
}

export default Contact;
